INSERT [dbo].[Course] ([CourseId], [CourseCategoryId], [Title], [ShortDescription], [LongDescription], [DifficultyLevel], [Status], [ThumbnailMediaId], [CreatedAt], [UpdatedAt], [TutorUserId], [IsActive]) VALUES (2, 2, N'English A2 – Everyday Communication', N'Pre-intermediate English course focused on daily conversations and practical language use.', N'This A2-level course expands vocabulary, improves speaking confidence and introduces students to more complex everyday situations. Topics include travel, shopping, simple opinions, and basic social interactions. Ideal for learners who already understand simple phrases and want to progress further.', N'A2', N'Published', 2, CAST(N'2025-12-05T18:21:12.8691753' AS DateTime2), CAST(N'2025-12-20T11:07:49.7477040' AS DateTime2), 5, 1)
