INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (1, 1, N'text', N'{"title":"Saying Hello","text":"In this lesson you will practice basic greetings: Hello, Hi, Good morning, Good afternoon, Good evening, Goodbye. Read and answer the questions below."}', 1, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (2, 1, N'single_choice', N'{"question":"It is 8:00 AM. What do you say?","options":["Good morning","Good evening","Good night","Goodbye"],"correctIndex":0,"explanation":"8:00 AM is morning → Good morning."}', 2, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (3, 1, N'single_choice', N'{"question":"You meet your friend at school. What is the best greeting?","options":["Good afternoon","Hi","Good night","Goodbye"],"correctIndex":1,"explanation":"With friends we usually say: Hi / Hello."}', 3, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (4, 1, N'fill_blank', N'{"prompt":"Complete the dialogue: \"Hello!\" — \"____!\"","answer":"Hi","caseSensitive":false,"explanation":"A natural short answer to Hello is: Hi! (also: Hello!)"}', 4, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (5, 1, N'text', N'{"title":"Quick recap","text":"Great job! Remember:\n- Morning: Good morning\n- Afternoon: Good afternoon\n- Evening: Good evening\n- Friends: Hi / Hello\nTry saying these out loud 3 times. When you feel ready, re-open the lesson and aim for 100% progress."}', 5, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (6, 2, N'text', N'{"title": "Daily Routine", "text": "In this lesson you will learn how to talk about your daily routine using simple present tense. We use simple present to describe things we do every day, regularly, or usually.\n\nExample:\nI wake up at 7 a.m.\nI go to work every day."}', 1, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (7, 2, N'single_choice', N'{"question": "Which sentence is correct?", "options": [ "I wakes up at 7 a.m.", "I wake up at 7 a.m.", "I waking up at 7 a.m." ], "correctIndex": 1, "explanation": "With I / you / we / they we use the base form of the verb: wake up."}', 2, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (8, 2, N'fill_blank', N'{"prompt": "Every morning I ____ breakfast at home.", "answer": "eat", "caseSensitive": false, "explanation": "In Simple Present we say: I eat breakfast."}', 3, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (9, 2, N'single_choice', N'{"question": "Choose the correct sentence:", "options": [ "She go to work at 8 a.m.", "She goes to work at 8 a.m.", "She going to work at 8 a.m." ], "correctIndex": 1, "explanation": "With he / she / it we add -s or -es: goes."}', 4, 1)
INSERT [dbo].[LessonContentBlock] ([LessonContentBlockId], [LessonId], [BlockType], [Content], [OrderIndex], [IsActive]) VALUES (10, 2, N'fill_blank', N'{"prompt": "He ____ home at 5 p.m.", "answer": "comes", "caseSensitive": false, "explanation": "With he / she / it we add -s: comes."}', 5, 1)
