INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (1, N'home', N'hero', N'{ "title": "Ucz się języków", "highlight": "na swoich zasadach", "description": "Lingrow to platforma e-learningowa, która pozwala Ci uczyć się języka angielskiego, realizować kursy krok po kroku i śledzić postępy w jednym miejscu.", "bullets": [ "Elastyczny grafik – uczysz się wtedy, kiedy masz czas.", "Interaktywne lekcje, quizy i system punktów za postępy.", "Dostęp z komputera i urządzeń mobilnych." ], "primaryCta": {"label": "Zaczynam naukę", "to": "/login"}, "secondaryCta": {"label": "Zobacz jak to działa", "hash": "how-it-works"} }', NULL, 1, 1, 7, CAST(N'2025-12-26T19:00:16.5750752' AS DateTime2))
INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (2, N'home', N'howItWorks', N'{ "sectionId": "how-it-works", "title": "Jak działa Lingrow?", "items": [ {"title": "1. Wybierasz kurs", "text": "Zaloguj się, przejrzyj dostępne kursy i wybierz ścieżkę dopasowaną do Twojego poziomu – od A1 do C1."}, {"title": "2. Realizujesz lekcje", "text": "Każdy kurs składa się z modułów, lekcji i quizów. System sam pilnuje postępu i przypomina o kolejnych zadaniach."}, {"title": "3. Zdajesz quiz", "text": "Tutor widzi Twoje wyniki i przygotowuje zajęcia pod Ciebie. Dzięki temu szybciej przełamujesz barierę mówienia."} ] }', NULL, 2, 1, 7, CAST(N'2025-12-26T19:01:13.7060834' AS DateTime2))
INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (3, N'home', N'benefits', N'{ "sectionId": "benefits", "title": "Dlaczego warto uczyć się z Lingrow?", "items": [ {"icon": "userClock", "title": "Nauka na żądanie", "text": "Uczysz się, kiedy możesz – rano, wieczorem, w weekend. Platforma działa 24/7."}, {"icon": "laptop", "title": "Zero dojazdów", "text": "Wszystko odbywa się online – wystarczy komputer lub tablet i stabilne łącze."}, {"icon": "mobile", "title": "Wygodna aplikacja", "text": "Projekt jest gotowy pod aplikację mobilną – możesz uczyć się w drodze do pracy lub na uczelnię."}, {"icon": "globe", "title": "Różne akcenty", "title": "Różne akcenty", "text": "Tutorzy z różnych krajów pomagają osłuchać się z prawdziwą komunikacją."} ] }', NULL, 3, 1, 7, CAST(N'2025-12-26T19:01:34.8284349' AS DateTime2))
INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (4, N'home', N'cta', N'{ "title": "Gotowy, żeby przenieść swoją naukę języka na wyższy poziom?", "description": "Załóż konto, wybierz kurs i zobacz, jak wygląda nowoczesna platforma e-learningowa przygotowana na potrzeby młodzieży i dorosłych.", "cta": {"label": "Dołącz do Lingrow", "to": "/login"} }', NULL, 4, 1, 7, CAST(N'2025-12-26T19:01:49.3147706' AS DateTime2))
INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (5, N'home', N'carouselSlide', N'{"label": "Pewność siebie", "title": "Pewność siebie w środowisku międzynarodowym", "description": "Realizujesz lekcje i quizy w uporządkowanej formie, co pozwala systematycznie rozwijać umiejętności językowe i budować pewność siebie w praktycznym użyciu języka."}', 4, 5, 1, 7, CAST(N'2025-12-26T19:03:19.7498231' AS DateTime2))
INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (6, N'home', N'carouselSlide', N'{"label": "Kariera", "title": "Nowe możliwości zawodowe", "description": "Lepsze rozmowy rekrutacyjne, prezentacje i codzienna komunikacja w firmie. Angielski przestaje Cię blokować w rozwoju."}', 5, 6, 1, 7, CAST(N'2025-12-26T19:03:41.4189616' AS DateTime2))
INSERT [dbo].[PageContentBlock] ([PageContentBlockId], [PageKey], [BlockType], [Content], [MediaFileId], [OrderIndex], [IsActive], [UpdatedByUserId], [UpdatedAt]) VALUES (7, N'home', N'carouselSlide', N'{"label": "Podróże", "title": "Swoboda w podróży i za granicą", "description": "Od zamawiania kawy po pytanie o drogę – czujesz się pewnie, gdziekolwiek jesteś. Uczysz się praktycznego języka."}', 6, 7, 1, 7, CAST(N'2025-12-26T19:04:37.7973881' AS DateTime2))
